command.text:
        &CommandToolSupplyLockedBeforeEdit;

declare @message nvarchar(4000)
select @message = 'setForm$TSAllocationCoefficient(this);loadForm$TSAllocationCoefficient(this);'
&CommandWhenToolSupplyExternalBeforeEdit;
select @message as message
return

        &CommandToolSupplyLockedBeforeEdit;

declare @message nvarchar(4000)
select @message = 'setForm$TSAllocationCoefficient(this);'
&CommandWhenToolSupplyExternalBeforeEdit;
select @message as message
return

        /* <flatten type="Javascript"> */
var f = this, o1 = f.getItem('ngay_hl_tu'), o2 = f.getItem('ngay_hl_den');
var errorMessage = (f._language == 'v' ? 'Trường <span class="Highlight">' + o1.field.HeaderText + '</span> phải nhỏ hơn hoặc bằng <span class="Highlight">' + o2.field.HeaderText + '</span>.' : '<span class="Highlight">' + o1.field.HeaderText + '</span> must be less than or equal to <span class="Highlight">' + o2.field.HeaderText + '</span>.');
if (f.getItemValue('ngay_hl_tu') > f.getItemValue('ngay_hl_den')) {
  $func.hideWait(f.get_id());
  f._checked = false;
  $message.show(errorMessage, String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), o1.field.Name));
}
/* </flatten> */

script.text:
      /* <flatten type="Javascript"> */
function setForm$TSAllocationCoefficient(f) {
  if (f._action != 'View') f._setReadOnly(f.getItem('ma_dc'), f._action == 'Edit' && !f.getItemValue('dv_yn'));
  if (f._action == 'Edit') {
    if (!f.getItemValue('dv_yn')) try {f.getItem('ma_bp_dc').focus();} catch (ex) {}
  }
}
function loadForm$TSAllocationCoefficient(f) {f.add_onResponseComplete(on$TSAllocationCoefficient$ResponseComplete);}
function closingForm$TSAllocationCoefficient(f) {try {f.remove_onResponseComplete(on$TSAllocationCoefficient$ResponseComplete);} catch (ex) {}}
function onChange$TSAllocationCoefficient(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('ma_bp_dc');
  f.request('TSCode', 'TSCode', ['ma_dc', 'ma_bp_dc'], o);
}
function onChange$DepartmentAllocationCoefficient(o) {o.parentForm.request('Department', 'Department', ['ma_dc', 'ma_bp_dc'], o);}
function on$TSAllocationCoefficient$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'TSCode':
      f.setItemValue('ma_dvcs', result[0].Value);
      f.setItemControlBehavior('tk_pb', result[1].Value, result[2].Value, true);
      f.setItemControlBehavior('tk_cp', result[3].Value, result[4].Value, true);
      break;
    case 'Department':
      f.setItemControlBehavior('tk_pb', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('tk_cp', result[2].Value, result[3].Value, true);
      break;
    default:
      break;
  }
}
/* </flatten> */
